const swiper2 = new Swiper('.swiper-type-2', {
  direction: 'horizontal',
  loop: false,
  autoplay: {
    delay: 3000,
    disableOnInteraction: true,
  },
  pagination: {
    el: '.pagination-2',
    clickable: true,
  },
  navigation: {
    nextEl: '.btn-next-2',
    prevEl: '.btn-prev-2',
  },
});

css:
/* Swiper Type 02 Styles */
.swiper-type-2 {
  width: 100%;
  border-radius: 20px;
  overflow: hidden;
}

.gradient-4 { background: linear-gradient(135deg, #11998e 0%, #38ef7d 100%); }
.gradient-5 { background: linear-gradient(135deg, #7F00FF 0%, #E100FF 100%); }
.gradient-6 { background: linear-gradient(135deg, #396afc 0%, #2948ff 100%); }

.control-center {
  display: flex;
  align-items: center;
  gap: 12px;
}

.autoplay-toggle-btn {
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  background-color: #f1f5f9;
  color: #64748b;
  border: none;
  cursor: pointer;
  transition: all 0.2s ease;
}
